// generar_232_seguimientos_y_recordatorios.js
// CHIQUI Entre Señales — Seguimientos pendientes y recordatorios
// inteligentes dentro de Novedades
//
// IMPORTANTE: este script se construye SOBRE el generar_231. Si aún no
// corriste el 231, córrelo PRIMERO y después este.
//
// Qué hace:
// 1) DESAPARECEN dos tarjetas fijas del dashboard:
//    - "En observación" (la enfermedad/observación abierta ya no se
//      muestra permanentemente)
//    - La pregunta rotativa ("¿Recuerdas cuándo comió bien...?")
// 2) SEGUIMIENTOS PENDIENTES (prioridad 5 de Novedades): cada
//    observación ACTIVA que lleve 15+ días sin evolución genera una
//    novedad: "🩺 Hace 18 días que no actualizas el seguimiento de
//    \"grano en la pata\". ¿Cómo sigue Luna?" → lleva a Salud
//    Preventiva. Al registrar una evolución, desaparece sola; si el
//    caso sigue abierto, reaparece cada 15 días (aunque se haya
//    cerrado la tarjeta) hasta marcarlo como resuelto.
// 3) RECORDATORIOS INTELIGENTES (prioridad 7): aparecen SOLO cuando
//    aportan valor — el campo se registró alguna vez y lleva días sin
//    dato: 🍽️ apetito (3+ días) · 💧 agua (3+) · 💩 deposiciones (3+)
//    · ⚖️ peso (30+). Se muestra UNO por día (el más atrasado) y
//    desaparece al completar el registro correspondiente.
//    Nota: "cómo ha dormido" quedó fuera porque el sueño aún no existe
//    como campo de registro en la app.
// 4) Prioridades quedan: 1 cumpleaños · 2 aniversario · 3 fechas
//    especiales · 4 estado del registro · 5 seguimientos · 6 racha ·
//    7 recordatorio inteligente · 8 mensaje positivo · 9 notificaciones.
//
// No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_232_seguimientos_y_recordatorios.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/dashboard/page.tsx",
    base64: ""
  },
  {
    ruta: "components/DashboardContenido.tsx",
    base64: ""
  },
  {
    ruta: "components/Novedades.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 3 archivos escritos correctamente.')
  console.log('No hay SQL esta vez. Puedes hacer git add / commit / push directo.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
